const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const fromAddress = body.fromAddress || '';
const toAddress = body.toAddress || '';
const subject = body.subject || '';
const bodyPreview = (body.bodyPreview || '').substring(0, 500);

if (!tenantId || !fromAddress) {
  return [{ json: { success: false, error: 'tenantId et fromAddress requis' } }];
}

const classification = typeof body.classification === 'string' ? JSON.parse(body.classification) : (body.classification || {});

return [{ json: {
  tenantId,
  emailId: body.emailId || null,
  threadId: body.threadId || null,
  fromAddress,
  toAddress,
  subject,
  bodyPreview,
  hasAttachments: body.hasAttachments === true || body.hasAttachments === 'true',
  provider: body.provider || 'gmail',
  classification: JSON.stringify(classification),
  action: body.action || 'queued',
  source: body.source || 'ai-agent',
  matchedRuleId: body.matchedRuleId || null,
  replySubject: body.replySubject || null,
  replyBody: body.replyBody || null,
  replyHtml: body.replyHtml || null,
  replyConfidence: Number(body.replyConfidence) || 0,
  replyAction: body.replyAction || 'none',
  tokensUsed: Number(body.tokensUsed) || 0,
  valid: true
} }];

const inserted = $input.first().json;

return [{ json: {
  success: true,
  data: {
    message: 'Email log enregistre',
    logId: inserted.id || null,
    createdAt: inserted.created_at || new Date().toISOString()
  }
} }];
